const body = items[0].json;
const event_type = body.event_type || "";
const request_id = body.request_id || "782f9d5e-ca87-439f-a89c-8eb139f4a088";
const brand_id = body.brand_id || "brand_demo_001";
const campaign_id = body.campaign_id || "campaign_demo_001";
const requested_by = body.requested_by || "user_demo_001@example.com";
const callback_url = body.callback_url || "http://localhost:5678/mock-callback";
const payload = body.payload || {};
const metadata = body.metadata || {};

// Strictly declare the mapping of supported event types to local endpoints to satisfy validator
const routes = {
  "creative_asset.requested": {
    "module_id": "creative_asset_comfyui",
    "health_endpoint": "http://localhost:8188/health",
    "run_endpoint": "http://localhost:8188/run"
  },
  "content_pack.requested": {
    "module_id": "content_pack_generator",
    "health_endpoint": "http://localhost:8191/health",
    "run_endpoint": "http://localhost:8191/run"
  },
  "ads_pack.requested": {
    "module_id": "ads_pack_generator",
    "health_endpoint": "http://localhost:8192/health",
    "run_endpoint": "http://localhost:8192/run"
  },
  "crm_followup.requested": {
    "module_id": "crm_followup_generator",
    "health_endpoint": "http://localhost:8193/health",
    "run_endpoint": "http://localhost:8193/run"
  },
  "analytics_report.requested": {
    "module_id": "analytics_report_generator",
    "health_endpoint": "http://localhost:8194/health",
    "run_endpoint": "http://localhost:8194/run"
  }
};

const route = routes[event_type];
const is_supported = !!route;
const run_id = "run_dry_" + Math.random().toString(36).substring(2, 15);

return [{
  json: {
    "contract_version": "e2e_dry_run_v0.1",
    "run_id": run_id,
    "request_id": request_id,
    "event_type": event_type,
    "brand_id": brand_id,
    "campaign_id": campaign_id,
    "requested_by": requested_by,
    "callback_url": callback_url,
    "payload": payload,
    "metadata": metadata,
    "module_id": is_supported ? route.module_id : "n8n_event_router",
    "health_endpoint": is_supported ? route.health_endpoint : null,
    "run_endpoint": is_supported ? route.run_endpoint : null,
    "is_supported": is_supported,
    "simulate_outage": metadata.simulate_outage || false,
    "simulate_run_failure": metadata.simulate_run_failure || false,
    "simulate_approval_decision": metadata.simulate_approval_decision || "approved"
  }
}];

const original = $node["Code: Normalize Event"].json;
let status = "unavailable";
let healthRes = null;

try {
  healthRes = items[0].json;
} catch (e) {}

if (healthRes && healthRes.status === "healthy" && !original.simulate_outage) {
  status = "healthy";
}

return [{
  json: {
    ...original,
    "health_status": status
  }
}];

const original = $node["Code: Analyze Health"].json;
let runRes = null;
let status = "failed";

try {
  runRes = items[0].json;
} catch (e) {}

if (runRes && !original.simulate_run_failure) {
  const isError = runRes.error || runRes.status === "failed" || runRes.status === "rejected" || (runRes.statusCode && runRes.statusCode >= 400);
  const isSuccess = runRes.status === "mock_completed" || runRes.status === "QUEUED" || runRes.status === "completed" || runRes.status === "success" || runRes.status === "OK";
  if (!isError && isSuccess) {
    status = "completed";
  }
}

// Normalize response based on module type
let output = {};
if (original.module_id === "creative_asset_comfyui") {
  output = {
    "asset_preview": "mock://assets/workspace_generated_001.png",
    "mock_asset_url": "mock://assets/workspace_generated_001.png",
    "mock_output_path": "storage/assets/placeholder_workspace_001.png"
  };
} else if (original.module_id === "content_pack_generator") {
  output = {
    "posts": [
      {
        "post_id": 1,
        "content": "Make the switch to our brand new biodegradable cups today! #eco"
      }
    ]
  };
} else if (original.module_id === "ads_pack_generator") {
  output = {
    "headline": "10% Off Early Bird Registrations!",
    "body": "Don't miss our tech event. Sign up now and save big."
  };
} else if (original.module_id === "crm_followup_generator") {
  output = {
    "messages": [
      {
        "day": 1,
        "subject": "Welcome aboard!",
        "body": "Thank you for shopping with us."
      }
    ]
  };
} else if (original.module_id === "analytics_report_generator") {
  output = {
    "report_markdown": "## Performance Metrics\n- CTR: 2.4%\n- CPC: $0.45"
  };
}

return [{
  json: {
    ...original,
    "module_status": status,
    "module_response": runRes || {},
    "unified_callback_preview": {
      "contract_version": "unified_callback_v0.1",
      "request_id": original.request_id,
      "event_type": original.event_type,
      "brand_id": original.brand_id,
      "campaign_id": original.campaign_id,
      "module_id": original.module_id,
      "module_status": status === "completed" ? "mock_completed" : "failed",
      "approval_status": "pending_approval",
      "output": output,
      "errors": status === "completed" ? [] : [{ "message": "Stub request failed" }],
      "metadata": {
        "workflow": original.module_id + "_v1"
      },
      "source": "n8n_n11_e2e_dry_run_mock",
      "generated_at": new Date().toISOString(),
      "notes": "Generated output ready for approval gate review."
    }
  }
}];
